#include <stdio.h>
#include <string.h>

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    char cake[N][M+1];
    for (int i = 0; i < N; i++) {
        scanf("%s", cake[i]);
    }
    int prefixSum[N][M];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (i == 0 && j == 0) {
                prefixSum[i][j] = cake[i][j] - '0';
            } else if (i == 0) {
                prefixSum[i][j] = prefixSum[i][j-1] + cake[i][j] - '0';
            } else if (j == 0) {
                prefixSum[i][j] = prefixSum[i-1][j] + cake[i][j] - '0';
            } else {
                prefixSum[i][j] = prefixSum[i-1][j] + prefixSum[i][j-1] - prefixSum[i-1][j-1] + cake[i][j] - '0';
            }
        }
    }
    int count = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            for (int k = i; k < N; k++) {
                for (int l = j; l < M; l++) {
                    int currants = prefixSum[k][l];
                    if (i > 0) {
                        currants -= prefixSum[i-1][l];
                    }
                    if (j > 0) {
                        currants -= prefixSum[k][j-1];
                    }
                    if (i > 0 && j > 0) {
                        currants += prefixSum[i-1][j-1];
                    }
                    if (currants % 2 == 0) {
                        count++;
                    }
                }
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

