                } else if (j == 0) {
                    prefixSum[i][j] = prefixSum[i-1][j] + cake[i][j];
                } else {
                    prefixSum[i][j] = prefixSum[i-1][j] + prefixSum[i][j-1] - prefixSum[i-1][j-1] + cake[i][j];
                }
            }
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                for (int k = i; k < N; k++) {
